#include <stdio.h>
#include <stdlib.h>

int main() {
    int T = 1;
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        int* V = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &V[i]);
        }
        int R;
        scanf("%d", &R);
        for (int i = 0; i < R; i++) {
            int start, end;
            scanf("%d %d", &start, &end);
            int* count = (int*)calloc(100000001, sizeof(int));
            for (int j = start; j <= end; j++) {
                count[V[j]]++;
            }
            int ans = 0;
            for (int j = 0; j <= 100000000; j++) {
                if (count[j] > K) {
                    ans++;
                }
            }
            printf("%d\n", ans);
            free(count);
        }
        free(V);
    }
    return 0;
}

